let allEvents = [];
let expandedId = null;
appsmith.onReady(() => {
  // 1. Hook up the event listeners securely
  document.getElementById('f-entity').addEventListener('change', applyFilters);
  document.getElementById('f-type').addEventListener('change', applyFilters);
  document.getElementById('f-alert').addEventListener('change', applyFilters);
  document.getElementById('f-search').addEventListener('input', applyFilters);

  // Event delegation for table rows (since they are generated dynamically)
  document.getElementById('events-body').addEventListener('click', e => {
    const tr = e.target.closest('tr[data-id]');
    if (tr) {
      toggleDetail(tr.getAttribute('data-id'));
    }
  });

  // 2. Load and sort initial data (Latest to Top)
  const rawEvents = appsmith.model.events || [];
  allEvents = rawEvents.sort((a, b) => new Date(b.timestamp_iso) - new Date(a.timestamp_iso));
  updateStats();
  applyFilters();
});
appsmith.onModelChange(newModel => {
  // Load and sort new data (Latest to Top)
  const rawEvents = newModel.events || [];
  allEvents = rawEvents.sort((a, b) => new Date(b.timestamp_iso) - new Date(a.timestamp_iso));
  updateStats();
  applyFilters();
});
function updateStats() {
  const human = allEvents.filter(e => e.entity_type === 'HUMAN').length;
  const auto = allEvents.filter(e => e.entity_type === 'AUTOMATED').length;
  const agent = allEvents.filter(e => e.entity_type === 'AGENT').length;
  const alerts = allEvents.filter(e => e.behavioral_alerts).length;
  document.getElementById('st-total').textContent = allEvents.length;
  document.getElementById('st-human').textContent = human;
  document.getElementById('st-auto').textContent = auto;
  document.getElementById('st-agent').textContent = agent;
  document.getElementById('st-alerts').textContent = alerts;
}
function applyFilters() {
  const fEntity = document.getElementById('f-entity').value;
  const fType = document.getElementById('f-type').value;
  const fAlert = document.getElementById('f-alert').value;
  const fSearch = document.getElementById('f-search').value.toLowerCase();
  let filtered = allEvents.filter(e => {
    if (fEntity && e.entity_type !== fEntity) return false;
    if (fType && e.event_type !== fType) return false;
    if (fAlert && !(e.behavioral_alerts || '').includes(fAlert)) return false;
    if (fSearch) {
      const hay = JSON.stringify(e).toLowerCase();
      if (!hay.includes(fSearch)) return false;
    }
    return true;
  });
  renderTable(filtered);
}
function entityBadge(t) {
  const map = {
    HUMAN: 'badge-human',
    AUTOMATED: 'badge-automated',
    AGENT: 'badge-agent',
    UNKNOWN: 'badge-unknown'
  };
  const cls = map[t] || 'badge-unknown';
  return `<span class="badge ${cls}">${t || '—'}</span>`;
}
function eventBadge(t) {
  const map = {
    llm_call: 'badge-llm',
    tool_call: 'badge-tool',
    error: 'badge-error'
  };
  return `<span class="badge ${map[t] || 'badge-unknown'}">${t || '—'}</span>`;
}
const CRITICAL_ALERTS = new Set(['REGULATORY_PROBE', 'PROGRESSIVE_PROBE', 'TAKEOVER_ALERT']);
function alertPills(raw) {
  if (!raw) return '—';
  return raw.split('|').map(a => `<span class="alert-pill${CRITICAL_ALERTS.has(a) ? ' critical' : ''}">${a}</span>`).join('');
}
function signalPills(raw) {
  if (!raw) return '—';
  return raw.split('|').map(s => `<span class="signal-pill">${s}</span>`).join('');
}
function fmtTime(iso) {
  if (!iso) return '—';
  return String(iso).replace('T', ' ').replace('Z', '');
}
function renderTable(events) {
  const tbody = document.getElementById('events-body');
  if (!events.length) {
    tbody.innerHTML = `<tr><td colspan="10"><div class="empty">
      <strong>No events match the current filters or data is empty.</strong>
    </div></td></tr>`;
    return;
  }
  tbody.innerHTML = events.map(e => {
    const id = e.event_id || Math.random();
    return `
    <tr data-id="${id}">
      <td>${fmtTime(e.timestamp_iso)}</td>
      <td>${eventBadge(e.event_type)}</td>
      <td title="${e.email || ''}">${(e.user_id || '—').substring(0, 14)}</td>
      <td>${entityBadge(e.entity_type)}${e.entity_subtype ? `<br/><span style="font-size:.65rem;color:#8b949e">${e.entity_subtype}</span>` : ''}</td>
      <td title="${e.model || ''}">${(e.model || '—').replace('claude-', 'c-').replace('gpt-', 'g-')}</td>
      <td>${e.latency_ms != null && e.latency_ms !== '' ? e.latency_ms + ' ms' : '—'}</td>
      <td>${e.total_tokens != null && e.total_tokens !== '' ? e.total_tokens : '—'}</td>
      <td style="text-align:center">${e.session_turn_index != null && e.session_turn_index !== '' ? e.session_turn_index : '—'}</td>
      <td class="wrap">${signalPills(e.classification_signals)}</td>
      <td class="wrap">${alertPills(e.behavioral_alerts)}</td>
    </tr>
    <tr class="detail-row" id="detail-${id}" style="display:none">
      <td colspan="10">
        <div class="detail-box">
          <pre>${JSON.stringify(e, null, 2)}</pre>
        </div>
      </td>
    </tr>`;
  }).join('');
}
function toggleDetail(id) {
  if (expandedId && expandedId !== id) {
    const prev = document.getElementById('detail-' + expandedId);
    if (prev) prev.style.display = 'none';
  }
  const row = document.getElementById('detail-' + id);
  if (!row) return;
  const visible = row.style.display !== 'none';
  row.style.display = visible ? 'none' : 'table-row';
  expandedId = visible ? null : id;
}

